function LCityBuildingHud:RefreshHudData()
    local show = self._cityView._buildingMgr:GetBuildingShow(self._buildingRefId)
    ShowObject(self._hudObj.gameObject,show)
    if(show == false)then
        return
    end
    ShowObject(self._nameInfo.gameObject,false)
    -- ShowObject(self._iconInfo.gameObject,false)
    ShowObject(self._uplevelSlider.gameObject,false)
    ShowObject(self._upBoxSlider.gameObject,false)
    ShowObject(self._freeIconInfo.gameObject,false)
    ShowObject(self._levelName.gameObject,false)
    ShowObject(self._soldierbg_ima.gameObject,false)
    self.buildData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    local config = GameTable.BuildingRef[self._buildingRefId]
    --判断是不是需要显示等级
    --没建造和没等级概念的不需要显示等级
    if(self.buildData == nil or config.maxLevel <= 1)then
        --不显示等级
        ShowObject(self._nameInfo.gameObject,true)
        ShowObject(self._levelName.gameObject,false)
    else
        --需要显示等级
        ShowObject(self._nameInfo.gameObject,false)
        ShowObject(self._levelName.gameObject,true)
    end
    local buildLevel = 0;--默认未建造，0级

    if(self.buildData ~= nil)then
        --已经建造了
        buildLevel = self.buildData.level
        ShowObject(self._buildCreateTips.gameObject,false)
    else
        if self._buildingRefId == BuildingType.HuoLu then
            ShowObject(self._buildCreateTips.gameObject,false)
        else
            ShowObject(self._buildCreateTips.gameObject,true)
        end
    end
    if(self:CheckShowLevelUpSlider())then
        self:SetImage(self._title_ima,"build_tipdo")
        ShowObject(self._uplevelSlider.gameObject,true)
        local buildType = CtrlCenter.Building:GetBuildType(self._buildingRefId)
        local configData = GameTable.BuildingLvRef[buildType*1000+self.buildData.level]
        local needTime = CtrlCenter.Building:CalculateBuildTotalTime(configData.buildTime)
        local timeTick = CtrlCenter.Building:GetBuildUpGradeTime(self._buildingRefId);
        self:RefreshSlider(needTime,timeTick)
        self:RefreshHelpIconInfo()
        self:SetText(self._freeTxt,I18nText(9312))
        local buildFreeTime = CtrlCenter.Building:CalculateBuildFreeTime()
        ShowObject(self._freeIconInfo.gameObject,buildFreeTime >= timeTick)
        --self._cityView._buildingMgr:GetBuilding(self._buildingRefId):ResetBuildingState("building")
        MgrCenter.TimerMgr:StartTimer(self,0.1,false,-1, function()
            timeTick = timeTick - 0.1;
            self:RefreshSlider(needTime,timeTick)
            if self._freeIconInfo ~= nil then
                ShowObject(self._freeIconInfo.gameObject,buildFreeTime >= timeTick)
            end
            if(timeTick <= 0)then
                MgrCenter.TimerMgr:StopTimer(self)
                if(self._uplevelSlider == nil)then
                    return
                end
                ShowObject(self._uplevelSlider.gameObject,false)
                --self._cityView._buildingMgr:ShowLevelUpEffect(self._buildingRefId)
                --self._cityView._buildingMgr:GetBuilding(self._buildingRefId):ResetBuildingState("idle1")
            end
        end)
    elseif self:CheckProduction(BuildingTaskType.Soldier) then
        ShowObject(self._uplevelSlider.gameObject,true)
        ShowObject(self._soldierbg_ima.gameObject,true)
        local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
        local soldierRef = GameTable.SoldierRef[task.soldier]
        local totalTime = math.floor(soldierRef.traningT / 1000 * task.count)
        local quality = soldierRef.quality
        self:SetText(self._soldier_lvl,soldierRef.rank)
        self:SetImage(self._soldierbg_ima,"public_itembg" .. quality)
        self:SetImage(self._soldierLvlBg_ima,"barrack_level_" .. quality)
        self:SetImage(self._soldierIcon_ima,soldierRef.img)
        local needTime = totalTime 
        local timeTick = task.endTime - GetTimestamp()
        self:RefreshSlider(needTime,timeTick)
        MgrCenter.TimerMgr:StartTimer(self,1,false,-1, function()
            timeTick = timeTick - 1;
            self:RefreshSlider(needTime,timeTick)
            if(timeTick <= 0)then
                self:RefreshIconInfo()
                CtrlCenter.Building:FireEventBarrackTaskFinish()
                MgrCenter.TimerMgr:StopTimer(self)
                if(self._uplevelSlider == nil)then
                    return
                end
                ShowObject(self._uplevelSlider.gameObject,false)
            end
        end)
    elseif self:CheckProduction(BuildingTaskType.Science) then
        self:RefreshScienceInfo()
        ShowObject(self._uplevelSlider.gameObject,true)

        local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
        local scienceCfg = ModuleCenter.Science:GetScienceCfgById(task.scienceGroup)
        self:SetImage(self._title_ima, scienceCfg.icon)

        local remainTime = task.endTime - GetTimestamp()
        local totalTime = ModuleCenter.Science:GetScienceUplevelReallyCostTime(task.scienceGroup)
        self:RefreshSlider(totalTime, remainTime)
        MgrCenter.TimerMgr:StartTimer(self,0.05,false,-1, function()
            remainTime = task.endTime - GetTimestamp()
            self:RefreshSlider(totalTime, remainTime)
            if (remainTime <= 0) then
                self:RefreshScienceInfo()
                MgrCenter.TimerMgr:StopTimer(self)
                HandlerCenter.Building:BuildingProductionFinishReq(task.id)
                if(self._uplevelSlider == nil)then
                    return
                end
                ShowObject(self._uplevelSlider.gameObject,false)
            end
        end)
    else
        ShowObject(self._uplevelSlider.gameObject,false)
        if self._buildingRefId == BuildingType.TaiXueYuan then
            self:RefreshScienceInfo()
            local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
            if task == false then
                MgrCenter.TimerMgr:StopTimer(self)
            end
        end
    end

    if self:CheckWareHouseBox() then
        self:SetBoxSliderState(true)
        local boxTime = ModuleCenter.Building:GetBuildingBoxTime(self._buildingRefId)
        local timeTick = boxTime - GetTimestamp()
        self:RefreshBoxSlider(timeTick)
        MgrCenter.TimerMgr:StartTimer(boxStateTimer,1,false,-1, function()
            timeTick = timeTick - 1;
            self:RefreshBoxSlider(timeTick)
            if(timeTick <= 0)then
                self:RefreshBoxIconInfo()
                self:SetBoxSliderState(false)
                MgrCenter.TimerMgr:StopTimer(boxStateTimer)
            end
        end)
    end

    self:SetText(self._nameInfo_name,I18nText(config.name))
    self:SetText(self._levelName_name,I18nText(config.name))
    self:SetText(self._levelName_level,buildLevel)

    PJXUtil.RebuildLayout(self._nameInfo_name.transform);
    PJXUtil.RebuildLayout(self._nameInfo_bg.transform);
    PJXUtil.RebuildLayout(self._levelName_name.transform);
    PJXUtil.RebuildLayout(self._levelName.transform);
end

function LCityBuildingHud:SetBuildCreateTipsState(show)
    if self._buildCreateTips == nil then
        return
    end
    local buildData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    if not buildData then
        ShowObject(self._buildCreateTips.gameObject,show)
    end
end

function LCityBuildingHud:SetBoxSliderState(show)
    if self._upBoxSlider == nil then
        return
    end
    ShowObject(self._upBoxSlider.gameObject,show)
end

function LCityBuildingHud:CheckProduction(type)
    if self.buildData == nil then
        return false
    end
    local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
    if task then
        if task.taskType == type then
            local trainTimes = task.endTime
            if trainTimes > 0 and trainTimes > GetTimestamp() then
                return true
            end
        end
    end
    return false
end

function LCityBuildingHud:CheckWareHouseBox()
    if self.buildData == nil then
        return false
    end
    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef and buildingRef.type or 0
    if buildType == BuildingType.CangKu then
        local boxTime = ModuleCenter.Building:GetBuildingBoxTime(self._buildingRefId)
        if boxTime > 0 and boxTime > GetTimestamp() then
            return true
        end
    end
    return false
end

function LCityBuildingHud:RefreshIconInfo()
    if self._iconInfo == nil then
        return
    end
    
    if self._isSoldierFinishShow then
        MgrCenter.TimerMgr:StartTimer(soldierFinishTimer..self._buildingRefId,1,false,1, function()
            self._isSoldierFinishShow = false
            ShowObject(self._iconInfo.gameObject,false)
            ShowObject(self._iconSoldierBg_ima.gameObject,false)
            MgrCenter.TimerMgr:StopTimer(soldierFinishTimer..self._buildingRefId)
        end)
    else
        ShowObject(self._iconInfo.gameObject,false)
        ShowObject(self._iconSoldierBg_ima.gameObject,false)
    end

    local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
    local isFinish = false
    if task then
        if task.taskType == BuildingTaskType.Soldier then
            local trainTimes = task.endTime
            if trainTimes > 0 and trainTimes <= GetTimestamp() then
                local soldierRef = GameTable.SoldierRef[task.soldier]
                isFinish = true
                self._isSoldierFinishShow = true
                ShowObject(self._iconInfo.gameObject,true)
                ShowObject(self._iconSoldierBg_ima.gameObject,true)
                local quality = soldierRef.quality
                self:SetText(self._iconSoldier_lvl,soldierRef.rank)
                self:SetImage(self._iconSoldierBg_ima,"public_itembg" .. quality)
                self:SetImage(self._iconSoldierLvlBg_ima,"barrack_level_" .. quality)
                self:SetImage(self._iconSoldierIcon_ima,soldierRef.img)
            end
        end
    end
    if isFinish then
       MgrCenter.TimerMgr:StopTimer(soldierFinishTimer..self._buildingRefId)
    else
        self._isSoldierFinishShow = false
    end
end

function LCityBuildingHud:RefreshBoxIconInfo()
    --宝箱领取状态
    if self._boxIconInfo == nil then
        return
    end
    ShowObject(self._boxIconInfo.gameObject,false)
    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef and buildingRef.type or 0
    if buildType == BuildingType.CangKu then
        local boxTime = ModuleCenter.Building:GetBuildingBoxTime(self._buildingRefId)
        if boxTime > 0 and boxTime <= GetTimestamp() then
            ShowObject(self._boxIconInfo.gameObject,true)
        end
    end
end

function LCityBuildingHud:RefreshHelpIconInfo()
    --帮助领取状态
    if self._helpIconInfo == nil then
        return
    end
    ShowObject(self._helpIconInfo.gameObject,false)
    local hasGuild = CtrlCenter.Guild:HadGuild()
    if self:CheckShowLevelUpSlider() and hasGuild then
        local isHelp = ModuleCenter.Building:CheckBuildingIsHelp(self._buildingRefId)
        ShowObject(self._helpIconInfo.gameObject,not isHelp)
    end
end

function LCityBuildingHud:RefreshSlider(needTime,curTime)
    if(self._slider_time == nil or self._slider_slider == nil)then
        return
    end
    self:SetText(self._slider_time,LxUtil.FormatTimespanNumber(curTime))
    self:SetImageFillAmount(self._slider_slider,(needTime-curTime)/needTime)
end

function LCityBuildingHud:RefreshBoxSlider(curTime)
    if self._boxslider_time == nil then
        return
    end
    self:SetText(self._boxslider_time,LxUtil.FormatTimespanNumber(curTime))
end

