            local building = self._cityView._buildingMgr:GetBuilding(self._buildingRefId)
            if building then
                building:ExecuteClick()
            end
        end
    end

    if(self._buildFreeLvlBtn == nil)then
        self._buildFreeLvlBtn = freeIconBg.gameObject:AddComponent(typeof(ProjectX.CButton)) --创建气泡按钮
    end
    self._buildFreeLvlBtn.enabled = true
    self._buildFreeLvlBtn.OnClickHandler = function(go,pointerEventData)
        HandlerCenter.Building:BuildingAccelerateReq(self._buildingRefId,{})
    end

end
function LCityBuildingHud:GetLevelData()
    self._buildingData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    local buildLevel = 0;--默认未建造，0级
    if(self._buildingData ~= nil)then
        --已经建造
        buildLevel = self._buildingData.level;
    end
    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef.type;

    local refId = buildType * 1000 + buildLevel;
    local levelData = GameTable.BuildingLvRef[refId];
    return levelData
end
function LCityBuildingHud:UsePeopleSkill(skillId)
    local buildData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    if(buildData == nil)then
        return
    end
    local count = CtrlCenter.Building:GetBuildingPeopleNum(self._buildingRefId)
    if(count > 0)then
        --建筑里有人工作
        --判断在工作时间
        local timeState = CtrlCenter.City:GetCurTimeState()
        --timeState = 2
        if(timeState == 2)then
            --工作时间
            local talkList = {}
            for i, v in pairs(GameTable.PeopleTalkRef) do
                local type = string.split(v.type,"=")
                if(checknumber(type[1]) == 3 and checknumber(type[2]) == skillId)then
                    table.insert(talkList,v)
                end
            end
            local listCount = #talkList
            local text = ""
            if(listCount > 0)then
                if(listCount == 1)then
                    --只有一条数据
                    text = talkList[1].desc
                else
                    local random = math.random(1,listCount)
                    text = talkList[random].desc
                end
                self:SetText(self._textInfo_text,I18nText(text))
                --强制更新文本布局
                LxUiHelper.TextNewLine(self._textInfo_text,self._text_textRectTrans,self._text_textFitter,272)

                ShowObject(self._textInfo.gameObject,true)
                PJXUtil.RebuildLayout(self._textInfo_text.transform);
                self:ResetTimer()
                self.delayTimer =MgrCenter.TimerMgr:DelayTime(function()
                    self:HideChatText()
                    self:ResetTimer()
                end,self,self._talkShowTime,false)
            end
        end
    end
end

function LCityBuildingHud:HideChatText()
    ShowObject(self._textInfo.gameObject,false)
end
function LCityBuildingHud:ResetTimer()
    if(self.delayTimer ~= nil)then
        MgrCenter.TimerMgr:StopTimer(self)
        MgrCenter.TimerMgr:RemoveTimer(self.delayTimer)
        self.delayTimer = nil
    end
end
function LCityBuildingHud:SetIconClickCb(cb)
    self._iconClickCb = cb;
end

function LCityBuildingHud:Show(bShow)
    self._showState = bShow

end
function LCityBuildingHud:OnUpdate(deltaTime)
    if(CtrlCenter.City:GetCityView():GetCameraSize() == self._defaultCameraSize)then
        return
    end
    self._curCameraSize = CtrlCenter.City:GetCityView():GetCameraSize()
    local scale = 1 -(self._curCameraSize - self._defaultCameraSize) * self._scaleRadio
    if(scale > 1)then
        scale = 1
    end
    self._textInfo.transform.localScale = Vector3(scale,scale,scale)
    local followY = (self._curCameraSize - self._defaultCameraSize) * self._followRadio
    self._textInfo.transform.localPosition = Vector3(self._defaultTextPos.x,self._defaultTextPos.y + followY,self._defaultTextPos.z)
end
--- 召唤英雄
function LCityBuildingHud:RefreshCallHeroInfo()
    if self._buildTipsInfo == nil then
        return
    end
    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef and buildingRef.type or 0
    local lv = ModuleCenter.Building:GetBuildingLvl(self._buildingRefId)
    if buildType == BuildingType.ZhaoXianGe and lv > 0 then
        -- 优先级1，可阵营招募：iconItem_104105
        -- 优先级2，可高级招募：iconItem_104104
        -- 优先级3，可普通招募：iconItem_104103
        local isShow = false
        local iconRes = "iconItem_104103"
        isShow = CtrlCenter.HeroCall:CheckCallHeroRedByRefId(HeroCall_RefIds.Water, FuncIds.RaceCall)
        if isShow then
            iconRes = "iconItem_104105"
        else
            isShow = CtrlCenter.HeroCall:CheckCallHeroRedByRefId(HeroCall_RefIds.Higher, FuncIds.HigherCall)
            if isShow then
                iconRes = "iconItem_104104"
            else
                isShow = CtrlCenter.HeroCall:CheckCallHeroRedByRefId(HeroCall_RefIds.Common, FuncIds.CommonCall)
            end
        end
        if isShow then
            self:SetImage(self._buildTipsIcon, iconRes)
            ShowObject(self._buildTipsInfo.gameObject,true)
        else
            ShowObject(self._buildTipsInfo.gameObject,false)
        end
    end
end
