--- 大学科技
function LCityBuildingHud:RefreshScienceInfo()
    if self._buildTipsInfo == nil then
        return
    end

    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef and buildingRef.type or 0

    if buildType == BuildingType.TaiXueYuan then
        local isAtUplevelInfo = ModuleCenter.Science:GetIsAtUpLevel()
        ShowObject(self._buildTipsInfo.gameObject,false)
        if isAtUplevelInfo.isAtUpLevel then
            return
        end

        local isShow = ModuleCenter.Science:GetIsShowScienceCityIcon()
        if isShow then
            self:SetImage(self._buildTipsBg,"notice_bg")
            self:SetImage(self._buildTipsIcon, "notice_science")
            ShowObject(self._buildTipsInfo.gameObject,true)
        end
    end
end

function LCityBuildingHud:OnClickBuildTips()
    LxUiHelper.PlaySoundById(SoundNames.Common)
    local buildingRef = GameTable.BuildingRef[self._buildingRefId]
    local buildType = buildingRef and buildingRef.type or 0
    if buildType == BuildingType.ZhaoXianGe then
        local jumpType = HeroCall_RefIds.Common
        local isShow = CtrlCenter.HeroCall:CheckCallHeroRedByRefId(HeroCall_RefIds.Water, FuncIds.RaceCall)
        if isShow then
            jumpType = HeroCall_RefIds.Race
        else
            isShow = CtrlCenter.HeroCall:CheckCallHeroRedByRefId(HeroCall_RefIds.Higher, FuncIds.HigherCall)
            if isShow then
                jumpType = HeroCall_RefIds.Higher
            end
        end
        ShowPanel(UiNames.HeroSummons, {refId = jumpType})
    elseif buildType == BuildingType.ShangHang then
        ShowPanel(UiNames.Shop, {refId = ShopTagType.ItemSubShop})
    elseif buildType == BuildingType.YingHunDian then
        ShowPanel(UiNames.HeroCorrelation, {tabType = 2})
    elseif buildType == BuildingType.Arena then
        ShowPanel(UiNames.Arena)
    elseif buildType == BuildingType.NoticeBoard then
        local notice = gLxServerList:GetPlatformNotices()
        if(table.nums(notice) > 0)then
            CtrlCenter.Game:OnAlertSet(tostring(AlertRemainType.Day), BuildingType.NoticeBoard,"noticeBoardInfo")
            ShowPanel(UiNames.SystemNotice)
            self:RefreshNoticeInfo()
        else
            ShowSysMsg(I18nText(10305))
        end
    elseif buildType == BuildingType.TaiXueYuan then
        ShowPanel(UiNames.Science, {buildId = self._buildingRefId, isShowScienceTree = true})
    elseif buildType == BuildingType.JunYiSuo then
        local task = ModuleCenter.Building:GetProductionTask(self._buildingRefId)
        if task then
            HandlerCenter.Building:BuildingProductionFinishReq(task.id)
        end
    end
end

return LCityBuildingHud